For handlers #1 and #2, provide REAL implementations that call deps:

**sf-state-read.ts:**
```ts
import { registerHandler } from '../ToolDispatcher';

registerHandler('sf_state_read', async (args, context, deps) => {
  const workItemId = args.work_item_id as string;

  if (workItemId === 'all') {
    const all = await deps.stateManager?.getAllStates();
    return { success: true, work_items: all ?? {} };
  }

  if (!workItemId) {
    return { success: false, error: 'work_item_id required' };
  }

  const state = await deps.stateManager?.getState(workItemId);
  if (!state) {
    return { success: false, error: `${workItemId} not found` };
  }
  return { success: true, ...state };
});
```

**sf-state-transition.ts:**
```ts
import { registerHandler } from '../ToolDispatcher';

registerHandler('sf_state_transition', async (args, context, deps) => {
  const workItemId = args.work_item_id as string;
  const fromState = (args.from_state as string) ?? '';
  const toState = args.to_state as string;

  if (!workItemId || toState === undefined) {
    return { success: false, error: 'work_item_id and to_state required' };
  }

  if (!deps.workflowEngine) {
    return { success: false, error: 'WorkflowEngine not available' };
  }

  try {
    const result = await deps.workflowEngine.transitionFull({
      workItemId,
      fromState,
      toState,
      evidence: (args.evidence as string) ?? '',
      workflowType: args.workflow_type as string,
      transitionContext: args.transition_context as Record<string, unknown>,
      actor: context.agent ? { agentRole: context.agent, sessionId: context.sessionID } : null,
    });
    return { success: true, ...result };
  } catch (err) {
    return { success: false, error: (err as Error).message };
  }
});
```

### Step 4: Wire handleToolInvoke to use ToolDispatcher

Edit `D:\code\temp\SpecForge\packages\daemon-core\src\http\HTTPServer.ts`:

1. Add import at the top:
```ts
import { ToolDispatcher } from '../tools';
```

2. Add to HTTPServerDeps interface:
```ts
toolDispatcher?: ToolDispatcher;
```

3. Replace the `handleToolInvoke` method (around line 773) with:

```ts
private async handleToolInvoke(_req: http.IncomingMessage, res: http.ServerResponse, body: string): Promise<void> {
  let request: Partial<ToolInvokeRequest>;
  try {
    request = body ? JSON.parse(body) : {};
  } catch {
    this.sendJsonResponse(res, 400, this.errorBody('INVALID_JSON', 'Invalid JSON in request body'));
    return;
  }

  if (!request.tool) {
    this.sendJsonResponse(res, 400, this.errorBody('MISSING_TOOL', 'tool field required'));
    return;
  }

  // Try real dispatcher first
  if (this.deps.toolDispatcher) {
    try {
      const result = await this.deps.toolDispatcher.dispatch(request as ToolInvokeRequest);
      this.sendJsonResponse(res, 200, this.successBody(result));
    } catch (err) {
      const msg = (err as Error).message;
      if (msg.startsWith('Unknown tool:')) {
        this.sendJsonResponse(res, 404, this.errorBody('UNKNOWN_TOOL', msg));
      } else if (msg.startsWith('Permission denied:')) {
        this.sendJsonResponse(res, 403, this.errorBody('PERMISSION_DENIED', msg));
      } else {
        this.sendJsonResponse(res, 500, this.errorBody('TOOL_ERROR', msg));
      }
    }
    return;
  }

  // Fallback placeholder
  this.sendJsonResponse(res, 501, this.errorBody('NOT_IMPLEMENTED', `Tool dispatch not available for ${request.tool}`));
}
```

### Step 5: Wire ToolDispatcher in Daemon.ts

Edit `D:\code\temp\SpecForge\packages\daemon-core\src\daemon\Daemon.ts` to create and inject the ToolDispatcher:

Add import:
```ts
import { ToolDispatcher } from '../tools';
```

In constructor, after creating workflowEngine/stateManager/etc:
```ts
// Import handlers (side-effect: registers with HANDLER_TABLE)
import '../tools';

const toolDispatcher = new ToolDispatcher({
  stateManager: this.stateManager,
  workflowEngine: this.workflowEngine,
  eventLogger: this.eventLogger,
  eventBus: this.eventBus,
  permissionEngine: this.permissionEngine,
  cas: undefined,
  sessionRegistry: undefined,
});
```

Pass it to HTTPServer deps:
```ts
toolDispatcher: toolDispatcher,
```

### Important:
- Use the `write` tool to create new files
- Use the `edit` tool to modify existing files
- Read existing files before editing
- Keep all stubs functional (they should return valid responses, not throw)

